import React from 'react';
import { Link, useLocation } from 'react-router-dom';

// Heroicons SVGs (inline for simplicity)
const icons = {
  Home: (
    <svg className="w-5 h-5 mr-1 inline-block" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M3 12l9-9 9 9M4 10v10a1 1 0 001 1h3m10-11v10a1 1 0 01-1 1h-3m-6 0h6" /></svg>
  ),
  Generator: (
    <svg className="w-5 h-5 mr-1 inline-block" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M16 17l-4 4m0 0l-4-4m4 4V3" /></svg>
  ),
  Projects: (
    <svg className="w-5 h-5 mr-1 inline-block" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M9 17v-6a2 2 0 012-2h2a2 2 0 012 2v6m-6 0h6" /></svg>
  ),
  Docs: (
    <svg className="w-5 h-5 mr-1 inline-block" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M12 20h9" /><path strokeLinecap="round" strokeLinejoin="round" d="M12 4h9" /><path strokeLinecap="round" strokeLinejoin="round" d="M4 4h16v16H4z" /></svg>
  ),
  Settings: (
    <svg className="w-5 h-5 mr-1 inline-block" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M12 8v4l3 3" /><circle cx="12" cy="12" r="10" /></svg>
  ),
  SignUp: (
    <svg className="w-5 h-5 mr-1 inline-block" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M16 21v-2a4 4 0 00-8 0v2" /><circle cx="12" cy="7" r="4" /></svg>
  ),
  Logo: (
    <svg className="w-8 h-8 text-fuchsia-400 mr-2" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="2" /><path d="M8 12h8M12 8v8" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /></svg>
  ),
};

function Navbar() {
  const location = useLocation();
  const navItems = [
    { name: 'Home', path: '/' },
    { name: 'Generator', path: '/generator' },
    { name: 'Projects', path: '/projects' },
    { name: 'Docs', path: '/docs' },
    { name: 'Settings', path: '/settings' },
  ];
  return (
    <nav className="flex items-center justify-between bg-[#18181b] px-6 py-3 shadow-md w-full">
      {/* Left: Logo and Brand */}
      <div className="flex items-center flex-shrink-0">
        {icons.Logo}
        <span className="font-extrabold text-xl text-white tracking-wide">CodeGen AI</span>
      </div>
      {/* Center: Nav Links */}
      <div className="flex-1 flex justify-center">
        <div className="flex gap-2 md:gap-4">
          {navItems.map(item => (
            <Link
              key={item.path}
              to={item.path}
              className={`flex items-center px-3 py-2 rounded-lg font-medium transition-colors duration-200 text-base ${location.pathname === item.path ? 'bg-gradient-to-r from-fuchsia-600 to-blue-600 text-white shadow' : 'text-gray-300 hover:bg-[#23232a] hover:text-white'}`}
            >
              {icons[item.name]}
              {item.name}
            </Link>
          ))}
        </div>
      </div>
      {/* Right: Sign Up */}
      <div className="flex items-center">
        <Link
          to="/signup"
          className="flex items-center bg-gradient-to-r from-fuchsia-500 to-blue-500 text-white px-4 py-2 rounded-lg font-semibold shadow hover:scale-105 transition duration-300"
        >
          {icons.SignUp}
          Sign Up
        </Link>
      </div>
    </nav>
  );
}

export default Navbar;
